import React, { useMemo, useState } from "react";
import { Button, ButtonGroup } from "react-bootstrap";
import Project from "./Project";
import ProjectData from "./ProjectData";

export default function Portfolio() {
  const categories = useMemo(
    () => [...new Set(ProjectData.map((p) => p.category))].sort(),
    []
  );
  const [selectedCategory, setSelectedCategory] = useState("All");

  const filteredProjects = useMemo(() => {
    if (selectedCategory === "All") return ProjectData;
    return ProjectData.filter((p) => p.category === selectedCategory);
  }, [selectedCategory]);

  return (
    <div className="portfolio-page">
      <h1 className="page-title">Portfolio</h1>
      <p className="portfolio-intro text-muted">
        Filter by category. Each project links to a live demo and source code.
      </p>
      <ButtonGroup className="portfolio-filters mb-4 flex-wrap" role="group" aria-label="Project categories">
        <Button
          type="button"
          variant={selectedCategory === "All" ? "primary" : "outline-primary"}
          onClick={() => setSelectedCategory("All")}
        >
          All
        </Button>
        {categories.map((cat) => (
          <Button
            key={cat}
            type="button"
            variant={selectedCategory === cat ? "primary" : "outline-primary"}
            onClick={() => setSelectedCategory(cat)}
          >
            {cat}
          </Button>
        ))}
      </ButtonGroup>
      <Project projects={filteredProjects} />
    </div>
  );
}
